39	
40	static fz_output *
41	fz_new_output_to_tempfile(fz_context *ctx, char **namep)
42	{
43		fz_output *out = NULL;
44	#ifdef _WIN32
45		char namebuf[L_tmpnam];
46		int attempts = 0;
47	#else
48		char namebuf[] = "/tmp/fztmpXXXXXX";
49	#endif
50	
51	
52		fz_var(out);
53	
54	#ifdef _WIN32
55		/* Windows has no mkstemp command, so we have to use the old-style
56		 * tmpnam based system, and retry in the case of races. */
57		do
58		{
59			if (tmpnam(namebuf) == NULL)
60				fz_throw(ctx, FZ_ERROR_SYSTEM, "tmpnam failed");
61			fz_try(ctx)
62				out = fz_new_output_with_path(ctx, namebuf, 0);
63			fz_catch(ctx)
64			{
65				/* We might hit a race condition and not be able to
66				 * open the file because someone beats us to it. We'd
67				 * be unbearably unlucky to hit this 10 times in a row. */
68				attempts++;
69				if (attempts >= 10)
70					fz_rethrow(ctx);
71				else
72					fz_ignore_error(ctx);
73			}
74		}
75		while (out == NULL);
76	#else
77		{
78			FILE *file;
79			int fd = mkstemp(namebuf);
80	
81			if (fd == -1)
82				fz_throw(ctx, FZ_ERROR_SYSTEM, "Cannot mkstemp: %s", strerror(errno));
83			file = fdopen(fd, "w");
84			if (file == NULL)
85				fz_throw(ctx, FZ_ERROR_SYSTEM, "Failed to open temporary file");
86			out = fz_new_output_with_file_ptr(ctx, file);
87		}
88	#endif
89	
90		if (namep)
91		{
92			fz_try(ctx)
93				*namep = fz_strdup(ctx, namebuf);
94			fz_catch(ctx)
95			{
96				fz_drop_output(ctx, out);
97				unlink(namebuf);
98				fz_rethrow(ctx);
99			}
100		}
101	
102		return out;
103	}
