105	static char *
106	fz_new_tmpfile_from_stream(fz_context *ctx, fz_stream *stm)
107	{
108		char *name;
109		fz_output *out = fz_new_output_to_tempfile(ctx, &name);
110	
111		fz_try(ctx)
112		{
113			fz_write_stream(ctx, out, stm);
114			fz_close_output(ctx, out);
115		}
116		fz_always(ctx)
117			fz_drop_output(ctx, out);
118		fz_catch(ctx)
119		{
120			fz_free(ctx, name);
121			fz_rethrow(ctx);
122		}
123	
124		return name;
125	}
