127	static fz_stream *
128	fz_file_backed_stream(fz_context *ctx, fz_stream *stream)
129	{
130		const char *oname = fz_stream_filename(ctx, stream);
131		char *name;
132	
133		/* If the file has a name, it's already a file-backed stream.*/
134		if (oname)
135			return stream;
136	
137		/* Otherwise we need to make it one. */
138		name = fz_new_tmpfile_from_stream(ctx, stream);
139		fz_try(ctx)
140			stream = fz_open_file_autodelete(ctx, name);
141		fz_always(ctx)
142			fz_free(ctx, name);
143		fz_catch(ctx)
144			fz_rethrow(ctx);
145	
146		return stream;
147	}
