149	struct fz_document_handler_context
150	{
151		int refs;
152		int count;
153		const fz_document_handler *handler[FZ_DOCUMENT_HANDLER_MAX];
154	};
155	
156	void fz_new_document_handler_context(fz_context *ctx)
157	{
158		ctx->handler = fz_malloc_struct(ctx, fz_document_handler_context);
159		ctx->handler->refs = 1;
160	}
161	
162	fz_document_handler_context *fz_keep_document_handler_context(fz_context *ctx)
163	{
164		if (!ctx || !ctx->handler)
165			return NULL;
166		return fz_keep_imp(ctx, ctx->handler, &ctx->handler->refs);
167	}
168	
169	void fz_drop_document_handler_context(fz_context *ctx)
170	{
171		int i;
172	
173		if (!ctx || !ctx->handler)
174			return;
175	
176		for (i = 0; i < ctx->handler->count; i++)
177		{
178			if (ctx->handler->handler[i]->fin)
179			{
180				fz_try(ctx)
181					ctx->handler->handler[i]->fin(ctx, ctx->handler->handler[i]);
182				fz_catch(ctx)
183					fz_ignore_error(ctx);
184			}
185		}
186	
187		if (fz_drop_imp(ctx, ctx->handler, &ctx->handler->refs))
188		{
189			fz_free(ctx, ctx->handler);
190			ctx->handler = NULL;
191		}
192	}
193	
194	void fz_register_document_handler(fz_context *ctx, const fz_document_handler *handler)
195	{
196		fz_document_handler_context *dc;
197		int i;
198	
199		if (!handler)
200			return;
201	
202		dc = ctx->handler;
203		if (dc == NULL)
204			fz_throw(ctx, FZ_ERROR_ARGUMENT, "Document handler list not found");
205	
206		for (i = 0; i < dc->count; i++)
207			if (dc->handler[i] == handler)
208				return;
209	
210		if (dc->count >= FZ_DOCUMENT_HANDLER_MAX)
211			fz_throw(ctx, FZ_ERROR_LIMIT, "Too many document handlers");
212	
213		dc->handler[dc->count++] = handler;
214	}
