216	const fz_document_handler *
217	fz_recognize_document_stream_content(fz_context *ctx, fz_stream *stream, const char *magic)
218	{
219		return fz_recognize_document_stream_and_dir_content(ctx, stream, NULL, magic);
220	}
221	
222	static const fz_document_handler *
223	do_recognize_document_stream_and_dir_content(fz_context *ctx, fz_stream **streamp, fz_archive *dir, const char *magic, void **handler_state, fz_document_recognize_state_free_fn **handler_free_state)
224	{
225		fz_document_handler_context *dc;
226		int i, best_score, best_i;
227		void *best_state = NULL;
228		fz_document_recognize_state_free_fn *best_free_state = NULL;
229		const char *ext;
230		int drop_stream = 0;
231		fz_stream *stream = *streamp;
232	
233		if (handler_state)
234			*handler_state = NULL;
235		if (handler_free_state)
236			*handler_free_state = NULL;
237	
238		dc = ctx->handler;
239		if (dc->count == 0)
240			fz_throw(ctx, FZ_ERROR_ARGUMENT, "No document handlers registered");
241	
242		if (magic == NULL)
243			magic = "";
244		ext = strrchr(magic, '.');
245		if (ext)
246			ext = ext + 1;
247		else
248			ext = magic;
249	
250		best_score = 0;
251		best_i = -1;
252	
253		/* If we're handed a stream, check to see if any of our document handlers
254		 * need a file. If so, change the stream to be a file-backed one. */
255		if (stream)
256		{
257			int wants_file = 0;
258			for (i = 0; i < dc->count; i++)
259				wants_file |= dc->handler[i]->wants_file;
260	
261			/* Convert the stream into a file_backed stream. */
262			if (wants_file)
263			{
264				fz_stream *stream2 = fz_file_backed_stream(ctx, stream);
265				if (stream2 != stream)
266				{
267					/* Either we need to pass this back to our caller, or we
268					 * need to drop it. */
269					drop_stream = 1;
270					stream = stream2;
271				}
272			}
273		}
274	
275		fz_try(ctx)
276		{
277			int can_recognize_stream = ((stream && stream->seek != NULL) || (stream == NULL && dir != NULL));
278	
279			for (i = 0; i < dc->count; i++)
280			{
281				void *state = NULL;
282				fz_document_recognize_state_free_fn *free_state = NULL;
283				int score = 0;
284				int magic_score = 0;
285				const char **entry;
286	
287				/* Get a score from recognizing the stream */
288				if (dc->handler[i]->recognize_content && can_recognize_stream)
289				{
290					if (stream)
291						fz_seek(ctx, stream, 0, SEEK_SET);
292					fz_try(ctx)
293					{
294						score = dc->handler[i]->recognize_content(ctx, dc->handler[i], stream, dir, &state, &free_state);
295					}
296					fz_catch(ctx)
297					{
298						/* in case of zip errors when recognizing EPUB/XPS/DOCX files */
299						fz_rethrow_unless(ctx, FZ_ERROR_FORMAT);
300						(void)fz_convert_error(ctx, NULL); /* ugly hack to silence the error message */
301						score = 0;
302					}
303				}
304	
305				/* Now get a score from recognizing the magic */
306				if (dc->handler[i]->recognize)
307					magic_score = dc->handler[i]->recognize(ctx, dc->handler[i], magic);
308	
309				for (entry = &dc->handler[i]->mimetypes[0]; *entry; entry++)
310					if (!fz_strcasecmp(magic, *entry))
311					{
312						magic_score = 100;
313						break;
314					}
315	
316				if (ext)
317				{
318					for (entry = &dc->handler[i]->extensions[0]; *entry; entry++)
319						if (!fz_strcasecmp(ext, *entry))
320						{
321							magic_score = 100;
322							break;
323						}
324				}
325	
326				/* If we recognized the format (at least partially), and the magic_score matches, then that's
327				 * definitely the one we want to use. Use 100 + score here, to allow for having multiple
328				 * handlers that support a given magic, where one agent is better than the other. */
329				if (score > 0 && magic_score > 0)
330					score = 100 + score;
331				/* Otherwise, if we didn't recognize the format, we'll weakly believe in the magic, but
332				 * we won't let it override anything that actually will cope. */
333				else if (magic_score > 0)
334					score = 1;
335				if (best_score < score)
336				{
337					best_score = score;
338					best_i = i;
339					if (best_free_state)
340						best_free_state(ctx, best_state);
341					best_free_state = free_state;
342					best_state = state;
343				}
344				else if (free_state)
345					free_state(ctx, state);
346			}
347			if (stream)
348				fz_seek(ctx, stream, 0, SEEK_SET);
349		}
350		fz_catch(ctx)
351		{
352			if (best_free_state)
353				best_free_state(ctx, best_state);
354			if (drop_stream)
355				fz_drop_stream(ctx, stream);
356			fz_rethrow(ctx);
357		}
358	
359		if (best_i < 0)
360		{
361			if (drop_stream)
362				fz_drop_stream(ctx, stream);
363			return NULL;
364		}
365	
366		/* Only if we found a handler, do we make our modified stream available to the
367		 * caller. */
368		*streamp = stream;
369	
370		if (handler_state && handler_free_state)
371		{
372			*handler_state = best_state;
373			*handler_free_state = best_free_state;
374		}
375		else if (best_free_state)
376			best_free_state(ctx, best_state);
377	
378		return dc->handler[best_i];
379	}
