381	const fz_document_handler *
382	fz_recognize_document_stream_and_dir_content(fz_context *ctx, fz_stream *stream, fz_archive *dir, const char *magic)
383	{
384		fz_stream *stm = stream;
385		const fz_document_handler *res;
386	
387		res = do_recognize_document_stream_and_dir_content(ctx, &stm, dir, magic, NULL, NULL);
388	
389		if (stm != stream)
390			fz_drop_stream(ctx, stm);
391	
392		return res;
393	}
