395	static const fz_document_handler *do_recognize_document_content(fz_context *ctx, const char *filename, void **handler_state, fz_document_recognize_state_free_fn **handler_free_state)
396	{
397		fz_stream *stream = NULL;
398		const fz_document_handler *handler = NULL;
399		fz_archive *zip = NULL;
400		fz_stream *stm;
401	
402		if (fz_is_directory(ctx, filename))
403			zip = fz_open_directory(ctx, filename);
404		else
405			stream  = fz_open_file(ctx, filename);
406	
407		stm = stream;
408		fz_try(ctx)
409			handler = do_recognize_document_stream_and_dir_content(ctx, &stm, zip, filename, handler_state, handler_free_state);
410		fz_always(ctx)
411		{
412			if (stm != stream)
413				fz_drop_stream(ctx, stm);
414			fz_drop_stream(ctx, stream);
415			fz_drop_archive(ctx, zip);
416		}
417		fz_catch(ctx)
418			fz_rethrow(ctx);
419	
420		return handler;
421	}
