438	fz_document *
439	fz_open_accelerated_document_with_stream_and_dir(fz_context *ctx, const char *magic, fz_stream *stream, fz_stream *accel, fz_archive *dir)
440	{
441		const fz_document_handler *handler;
442		fz_stream *wrapped_stream = stream;
443		fz_document *ret;
444		void *state = NULL;
445		fz_document_recognize_state_free_fn *free_state = NULL;
446	
447		if (stream == NULL && dir == NULL)
448			fz_throw(ctx, FZ_ERROR_ARGUMENT, "no document to open");
449		if (magic == NULL)
450			fz_throw(ctx, FZ_ERROR_ARGUMENT, "missing file type");
451	
452		/* If this finds a handler, then this might wrap stream. If it does, we reuse the wrapped one in
453		 * the open call (hence avoiding us having to 'file-back' a stream twice), but we must free it. */
454		handler = do_recognize_document_stream_and_dir_content(ctx, &wrapped_stream, dir, magic, &state, &free_state);
455		if (!handler)
456			fz_throw(ctx, FZ_ERROR_UNSUPPORTED, "cannot find document handler for file type: '%s'", magic);
457		fz_try(ctx)
458			ret = handler->open(ctx, handler, wrapped_stream, accel, dir, state);
459		fz_always(ctx)
460		{
461			if (wrapped_stream != stream)
462				fz_drop_stream(ctx, wrapped_stream);
463			if (free_state && state)
464				free_state(ctx, state);
465		}
466		fz_catch(ctx)
467			fz_rethrow(ctx);
468	
469		return ret;
470	}
