504	fz_document *
505	fz_open_accelerated_document(fz_context *ctx, const char *filename, const char *accel)
506	{
507		const fz_document_handler *handler;
508		fz_stream *file = NULL;
509		fz_stream *afile = NULL;
510		fz_document *doc = NULL;
511		fz_archive *dir = NULL;
512		char dirname[PATH_MAX];
513		void *state = NULL;
514		fz_document_recognize_state_free_fn *free_state = NULL;
515	
516		if (filename == NULL)
517			fz_throw(ctx, FZ_ERROR_ARGUMENT, "no document to open");
518	
519		if (fz_is_directory(ctx, filename))
520		{
521			/* Cannot accelerate directories, currently. */
522			dir = fz_open_directory(ctx, filename);
523	
524			fz_try(ctx)
525				doc = fz_open_accelerated_document_with_stream_and_dir(ctx, filename, NULL, NULL, dir);
526			fz_always(ctx)
527				fz_drop_archive(ctx, dir);
528			fz_catch(ctx)
529				fz_rethrow(ctx);
530	
531			return doc;
532		}
533	
534		handler = do_recognize_document_content(ctx, filename, &state, &free_state);
535		if (!handler)
536			fz_throw(ctx, FZ_ERROR_UNSUPPORTED, "cannot find document handler for file: %s", filename);
537	
538		fz_var(afile);
539		fz_var(file);
540		fz_var(dir);
541	
542		fz_try(ctx)
543		{
544			file = fz_open_file(ctx, filename);
545	
546			if (accel)
547				afile = fz_open_file(ctx, accel);
548			if (handler->wants_dir)
549			{
550				fz_dirname(dirname, filename, sizeof dirname);
551				dir = fz_open_directory(ctx, dirname);
552			}
553			doc = handler->open(ctx, handler, file, afile, dir, state);
554		}
555		fz_always(ctx)
556		{
557			if (free_state)
558				free_state(ctx, state);
559			fz_drop_archive(ctx, dir);
560			fz_drop_stream(ctx, afile);
561			fz_drop_stream(ctx, file);
562		}
563		fz_catch(ctx)
564			fz_rethrow(ctx);
565	
566		return doc;
567	}
