764	void
765	fz_style_document(fz_context *ctx, fz_document *doc, int publisher_css, const char *user_css)
766	{
767		if (doc && doc->style)
768		{
769			/* Note: deprecated use of global fz_use_document_css and fz_user_css */
770			if  (doc->did_style == FZ_STYLE_NEEDS_DEFAULT)
771				doc->did_style = FZ_STYLE_NEEDS_UPDATE;
772	
773			if (doc->publisher_css != publisher_css)
774			{
775				doc->did_style = FZ_STYLE_NEEDS_UPDATE;
776				doc->publisher_css = publisher_css;
777			}
778	
779			if (user_css)
780			{
781				if (doc->user_css && !strcmp(doc->user_css, user_css))
782				{
783					// no change
784				}
785				else
786				{
787					doc->did_style = FZ_STYLE_NEEDS_UPDATE;
788					fz_free(ctx, doc->user_css);
789					doc->user_css = NULL;
790					doc->user_css = fz_strdup(ctx, user_css);
791				}
792			}
793			else
794			{
795				if (doc->user_css)
796				{
797					doc->did_style = FZ_STYLE_NEEDS_UPDATE;
798					fz_free(ctx, doc->user_css);
799					doc->user_css = NULL;
800				}
801			}
802	
803			if (doc->did_style == FZ_STYLE_NEEDS_UPDATE)
804				doc->did_layout = FZ_LAYOUT_NEEDS_UPDATE;
805		}
806	}
