859		int start = 0;
860		for (i = 0; i < n; ++i)
861		{
862			int m = fz_count_chapter_pages(ctx, doc, i);
863			if (number < start + m)
864				return fz_load_chapter_page(ctx, doc, i, number - start);
865			start += m;
866		}
867		fz_throw(ctx, FZ_ERROR_ARGUMENT, "invalid page number: %d", number+1);
