925	{
926		int i, m = 0, n = fz_count_chapters(ctx, doc);
927		int start = 0;
928		if (number < 0)
929			number = 0;
930		for (i = 0; i < n; ++i)
931		{
932			m = fz_count_chapter_pages(ctx, doc, i);
933			if (number < start + m)
934				return fz_make_location(i, number - start);
935			start += m;
936		}
937		return fz_make_location(i-1, m-1);
938	}
