1009	
1010		// Trigger reaping dead pages when we load a new page.
1011		fz_reap_dead_pages(ctx, doc);
1012	
1013		/* Protect modifications to the page list to cope with
1014		 * destruction of pages on other threads. */
1015		for (page = doc->open; page; page = page->next)
1016		{
1017			if (page->chapter == chapter && page->number == number)
1018			{
1019				fz_keep_page(ctx, page);
1020				return page;
1021			}
1022		}
1023	
1024		if (doc->load_page)
1025		{
1026			page = doc->load_page(ctx, doc, chapter, number);
1027			page->chapter = chapter;
1028			page->number = number;
1029	
1030			/* Insert new page at the head of the list of open pages. */
1031			if (!page->incomplete)
1032			{
1033				if ((page->next = doc->open) != NULL)
1034					doc->open->prev = &page->next;
1035				doc->open = page;
1036				page->prev = &doc->open;
1037				page->in_doc = 1;
